const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const connectDB = async () => {
  try {
    await mongoose.connect('mongodb://localhost:27017/your_database', {
      useNewUrlParser: true,
      useUnifiedTopology: true,
    });
    console.log('MongoDB connected');
  } catch (error) {
    console.error('MongoDB connection error:', error);
    process.exit(1);
  }
};

connectDB();

app.post('/search', async (req, res) => {
  try {
    const { collection, query, projection, options = {} } = req.body;
    
    if (!collection || !query) {
      return res.status(400).json({ error: 'Collection and query are required' });
    }
    
    const db = mongoose.connection.db;
    const collectionRef = db.collection(collection);
    
    const result = await collectionRef.find(query, projection).toArray();
    
    res.json({ data: result });
  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});